  logoutBtn: { width: '100%', padding: '8px', borderRadius: 7, border: '1px solid var(--border)', background: 'transparent', color: '#646464', fontSize: 12, cursor: 'pointer' },

  main: { flex: 1, overflow: 'auto' },
